
export function RtSome<T>(value: T) {
    return new RtOption<T>(value);
}

export function RtNone<T>() {
    return new RtOption<T>(null);
}
export class DataSourcePropertyKeyBuilder {
    static buildKey(dsName: string, fieldName: string) {
        return `${dsName}.${fieldName}`;
    }
}

export class RtOption<T> {

    private readonly value: T;

    constructor(value: T | undefined) {
        if (value !== undefined && value != null) {
            this.value = value;
        } else {
            this.value = undefined;
        }
    }

    public get isDefined(): boolean {
        return this.value !== undefined && this.value != null;
    }

    public get isEmpty(): boolean {
        return this.value === undefined || this.value == null;
    }

    public get get(): T {
        if (this.value !== undefined) {
            return this.value;
        } else {
            throw new Error('None.get error');
        }
    }

    // scala: @inline final def getOrElse[B >: A](default: => B): B =
    // if (isEmpty) default else this.get

    public getOrElse(fn: () => T): T {
        if (this.isEmpty)
            return fn();
        else return this.get;
    }

    public getOrElseThrow(errorMsg: string): T {
        if (this.isEmpty)
            throw new Error(errorMsg);
        else return this.get;
    }

    public getOrElseV2(alternativeValue: T): T {
        if (this.isEmpty)
            return alternativeValue;
        else return this.get;
    }

    public get getOrElseUndefined(): T {
        return this.getOrElse(() => undefined);
    }

    public get getOrElseNull(): T {
        return this.getOrElse(() => null);
    }

    //scala: def map[B, That](f: A => B): That
    //map[B](f: A => B): Option[B]
    public map<B>(fn: (t: T) => B): RtOption<B> {

        if (this.isDefined) {
            const value: B = fn(this.get);
            return RtSome(value);
        } else {
            return RtNone();
        }
    }

    public get toArray(): T[] {
        if (this.isDefined) {
            return [this.get];
        } else {
            return [];
        }
    }

    static parse<T>(val: RtOption<T>): RtOption<T> {
        const valObj = val as any as { value?: any; };
        if (valObj.value || valObj.value == 0) {
            return RtSome(valObj.value);
        }
        return RtNone();
    }
}
export class DsResultValue {
    constructor(public fieldName: string, public originalValue: any, public value: any, public uom: RtOption<string>, public referenceData: RtOption<unknown>) { }

    public get hasValue() {
        return this.value != null || this.referenceData.isDefined;
    }
    public get displayValue(): string {
        if (this.uom.isDefined) {
            return `${this.value} ${this.uom.get}`;
        }
        else {
            return this.referenceData.isDefined ? this.referenceData.get : this.value;
        }
    }

    asFullyQualifiedDsResultValue(dsName: string): DsResultValue {
        const fieldName = DataSourcePropertyKeyBuilder.buildKey(dsName, this.fieldName);
        return new DsResultValue(fieldName, this.originalValue, this.value, this.uom, this.referenceData);
    }

}


export enum DisplayBindingType {
    VALUE = "value",
    DISPLAY_VALUE = "display_value",
    UOM = "uom",
}
export class UomBinding {

    constructor(private _direct: RtOption<any>,
        private _uomOptions: RtOption<any>,
        private _rounding: RtOption<number>,) {
    }

    get direct(): any { return this._direct.getOrElseUndefined }


    set direct(value: any) { this._direct = RtSome(value) }

    get uomOptions(): any { return this._uomOptions.getOrElseUndefined }

    set uomOptions(value: any) { this._uomOptions = RtSome(value) }

    get rounding(): number { return this._rounding.getOrElseUndefined }

    set rounding(value: number) {
        this._rounding = RtSome(value)
    }

    static parse(uomBinding: UomBinding): UomBinding {
        const directValue = RtOption.parse(uomBinding._direct);
        const uomOptions = RtOption.parse(uomBinding._uomOptions);
        const rounding = RtOption.parse(uomBinding._rounding);
        const parsedUomBinding = new UomBinding(directValue, uomOptions, rounding);
        return parsedUomBinding;
    }
}

export class ControlPropertyDefinitionValue {
    constructor(
        public controlAttributeName: string,   // Label --> value //Image --> image
        public value?: any,  // Default Value ---> Name
        public dsPropertyName?: string | string[], // ---> Bounded property from Data Source e.g. EmployeeName  //Image --> ImageUrl
        public uomBinding?: UomBinding, // if the field is of type 'UOM', then uomBinding binding may contain the conversion strategy
        public displayBindingType?: DisplayBindingType,
        public cssTemplate?: string,
        public jsTemplate?: string,
        //public dsName?: string // Data Source name --> Vehicles, Trips etc
    ) { }

    static parse(controlPropertyDefinitionValue: ControlPropertyDefinitionValue) {
        const uomBinding = controlPropertyDefinitionValue.uomBinding ? UomBinding.parse(controlPropertyDefinitionValue.uomBinding) : undefined;
        const reConstructedObj = new ControlPropertyDefinitionValue(controlPropertyDefinitionValue.controlAttributeName,
            controlPropertyDefinitionValue.value,
            controlPropertyDefinitionValue.dsPropertyName,
            uomBinding,
            controlPropertyDefinitionValue.displayBindingType,
            controlPropertyDefinitionValue.cssTemplate,
            controlPropertyDefinitionValue.jsTemplate
        );
        return reConstructedObj;
    }
}
