export class IdentityGenerator {
    static MAGIC_BASE = 900000000000000;
    static getLongId(increment: number) {
        return IdentityGenerator.MAGIC_BASE + increment;
    }

    static guid() {
        function s4() {
            return Math.floor((1 + Math.random()) * 0x10000)
                .toString(16)
                .substring(1);
        }
        return s4() + s4() + '-' + s4() + '-' + s4() + '-' +
            s4() + '-' + s4() + s4() + s4();
    }
}